// TRF_PrepareContext - Prepare context with user prefs and LOCAL time
let envelope = $('TRG_FromOrchestrator').item.json.envelope;
const router = $('TRG_FromOrchestrator').item.json.router || {};
// GUARDRAIL: envelope pode vir como string (JSON stringified) do Orchestrator
if (typeof envelope === 'string') {
  try {
    envelope = JSON.parse(envelope);
  } catch(e) {
    envelope = { user_message: envelope, text_raw: envelope };
  }
}
const prefsResult = $('DB_FetchPrefs').all();
let lead_time_minutes = 15;
let timezone = 'America/Belem';
if (prefsResult && prefsResult.length > 0) {
  const prefs = prefsResult[0].json;
  lead_time_minutes = prefs.lead_time_minutes || 15;
  timezone = prefs.timezone || 'America/Belem';
}
const now = new Date();
const localTime = now.toLocaleString('pt-BR', { 
  timeZone: timezone,
  year: 'numeric', month: '2-digit', day: '2-digit',
  hour: '2-digit', minute: '2-digit', second: '2-digit',
  hour12: false
});
const tzOffset = timezone === 'America/Belem' ? -3 : -3;
const userMessage = envelope.user_message || envelope.text_raw || '';
// Montar o chatInput completo para o Agent
const chatInput = `Extraia os itens (lembretes, tarefas, notas) da mensagem do usuário.
MENSAGEM: ${userMessage}
DATA/HORA LOCAL: ${localTime}
FUSO HORÁRIO: ${timezone} (GMT${tzOffset})
Converta horários locais para UTC somando ${Math.abs(tzOffset)} horas.`;
return [{
  json: {
    envelope: envelope,
    router: router,
    user_message: userMessage,
    chatInput: chatInput,
    prefs: {
      lead_time_minutes: lead_time_minutes,
      timezone: timezone,
      tz_offset_hours: tzOffset,
      lead_time_scope: (prefsResult && prefsResult.length > 0) ? (prefsResult[0].json.lead_time_scope || '') : ''
    },
    current_time_local: localTime,
    current_time_utc: now.toISOString()
  }
}];

