// TRF_ProcessExtraction - Process extraction and prepare bulk create
const context = $('TRF_PrepareContext').item.json;
const agentOutput = $('Agent_Capture').item.json;
let items = [];
let needs_clarification = false;
let clarification_question = null;
try {
  let extractedData = agentOutput;
  if (agentOutput.output && typeof agentOutput.output === 'object') {
    extractedData = agentOutput.output;
  } else if (agentOutput.output && typeof agentOutput.output === 'string') {
    const cleaned = agentOutput.output.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    extractedData = JSON.parse(cleaned);
  }
  items = extractedData.items || [];
  needs_clarification = extractedData.needs_clarification || false;
  clarification_question = extractedData.clarification_question || null;
} catch (e) {
  needs_clarification = true;
  clarification_question = 'Desculpe, não consegui entender. Pode reformular?';
}
// Detecção de conteúdo sensível
const SENSITIVE_PATTERNS = [
  /senha/i, /password/i, /token/i, /api.?key/i,
  /\b\d{3}\.?\d{3}\.?\d{3}-?\d{2}\b/,
  /\b\d{2}\.?\d{3}\.?\d{3}\/?\d{4}-?\d{2}\b/,
  /cnh/i, /nascimento/i, /data.?de.?nasc/i,
  /\bbanco\b|\bconta\b|\bag[eê]ncia\b|\bpix\b/i, /cart[ãa]o/i,
  /\brg\b/i, /\bpis\b/i
];
function isSensitive(text) {
  if (!text) return false;
  for (const pattern of SENSITIVE_PATTERNS) {
    if (pattern.test(text)) return true;
  }
  return false;
}
// Truncar segundos
function truncateSeconds(dt) {
  if (!dt) return null;
  return dt.replace(/(\d{2}:\d{2}):\d{2}/, '$1:00');
}
const default_lead_time = context.prefs.lead_time_minutes || 15;
const source_message_id = context.envelope.provider_message_id || null;
const owner_phone = context.envelope.from_phone;
const completeItems = [];
const incompleteItems = [];
for (const item of items) {
  if (item.event_datetime) {
    item.event_datetime = truncateSeconds(item.event_datetime);
  }
  if (item.type === 'note' || item.type === 'task') {
    completeItems.push(item);
  } else if (item.type === 'reminder' && item.event_datetime) {
    completeItems.push(item);
  } else if (item.type === 'reminder' && !item.event_datetime) {
    item.type = 'task';
    completeItems.push(item);
  } else {
    incompleteItems.push(item);
  }
}
if (completeItems.length === 0 && needs_clarification) {
  return [{
    json: {
      envelope: context.envelope,
      needs_clarification: true,
      clarification_question: clarification_question,
      items_to_create: [],
      skip_bulk_create: true
    }
  }];
}
const items_to_create = completeItems.map(item => {
  let notification_datetime = null;
  let effective_lead_time = null;

  if (item.event_datetime && item.type === 'reminder') {
    const isRelative = item.is_relative === true;
    effective_lead_time = isRelative ? 0 : default_lead_time;

    const eventDate = new Date(item.event_datetime);
    notification_datetime = new Date(eventDate.getTime() - (effective_lead_time * 60 * 1000)).toISOString();
  }

  const combinedText = (item.title || '') + ' ' + (item.value || '');
  const sensitive = isSensitive(combinedText);

  return {
    type: item.type,
    title: item.title,
    value: item.value || null,
    event_datetime: item.event_datetime || null,
    notification_datetime: notification_datetime,
    lead_time_minutes: effective_lead_time,
    is_sensitive: sensitive,
    priority: item.priority || 'medium',
    tags: item.tags || [],
    status: 'open',
    owner_phone: owner_phone,
    source_message_id: source_message_id,
    // Google Calendar enhancement fields
    duration_minutes: item.duration_minutes || null,
    add_google_meet: item.add_google_meet || false,
    attendees: item.attendees || [],
    extra_reminders: item.extra_reminders || []
  };
});
const pendingClarification = (incompleteItems.length > 0 && needs_clarification) 
  ? clarification_question 
  : null;
return [{
  json: {
    envelope: context.envelope,
    needs_clarification: false,
    clarification_question: pendingClarification,
    items_to_create: items_to_create,
    skip_bulk_create: items_to_create.length === 0
  }
}];

// TRF_ReturnClarification - Return clarification question
const data = $('TRF_ProcessExtraction').item.json;

let responseText = data.clarification_question || 'Não encontrei itens para criar.';

return [{
  json: {
    envelope: data.envelope,
    agent_response: {
      text: responseText,
      agent: 'CAPTURE',
      created_count: 0,
      needs_clarification: true
    }
  }
}];

// Prepare ALL items for database insertion
const allInputs = $input.all();
return allInputs.map(inputItem => {
  const data = inputItem.json;
  const item = data.item || {};
  const envelope = data.envelope || {};

  return {
    json: {
      owner_phone: item.owner_phone || envelope.from_phone,
      type: item.type || 'note',
      title: item.title || 'Sem título',
      value: item.value || null,
      status: 'open',
      priority: item.priority || 'medium',
      event_datetime: item.event_datetime || null,
      notification_datetime: item.notification_datetime || null,
      lead_time_minutes: item.lead_time_minutes || null,
      is_sensitive: item.is_sensitive || false,
      source_message_id: item.source_message_id || null,
      tags: item.tags || [],
      // New fields for Google Calendar enhancements
      duration_minutes: item.duration_minutes || null,
      add_google_meet: item.add_google_meet || false,
      attendees: item.attendees || [],
      extra_reminders: item.extra_reminders || [],
      envelope: envelope
    }
  };
});

// DB_InsertItem V6 - insert one by one using secure env vars
const allInputs = $input.all();
const supabaseUrl = 'https://chtkfksjqcvlxpgyzlsf.supabase.co';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImNodGtma3NqcWN2bHhwZ3l6bHNmIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MjMwODU1NywiZXhwIjoyMDg3ODg0NTU3fQ.DM9wL7MlXRBuM_IYDk3pQ_q-WE7DYuwpqTTywg5A05U';

if (!supabaseUrl || !supabaseKey) {
  return allInputs.map((inputItem) => ({
    json: {
      ...inputItem.json,
      id: null,
      _db_insert_error: 'Missing SUPABASE_URL or SUPABASE_KEY environment variables'
    }
  }));
}

const headers = {
