  Authorization: 'Bearer ' + supabaseKey,
  'Content-Type': 'application/json',
  Prefer: 'return=representation'
};

const results = [];

for (const inputItem of allInputs) {
  const item = inputItem.json;
  const row = {
    owner_phone: item.owner_phone,
    type: item.type,
    title: item.title,
    value: item.value || null,
    event_datetime: item.event_datetime || null,
    notification_datetime: item.notification_datetime || null,
    lead_time_minutes: item.lead_time_minutes || null,
    is_sensitive: item.is_sensitive || false,
    source_message_id: item.source_message_id || null,
    priority: item.priority || 'medium',
    status: 'open'
  };

  try {
    const result = await this.helpers.httpRequest({
      method: 'POST',
      url: supabaseUrl + '/rest/v1/items',
      headers,
      body: row,
      json: true
    });

    const inserted = Array.isArray(result) ? result[0] : result;
    results.push({
      json: {
        ...item,
        id: inserted.id,
        created_at: inserted.created_at
      }
    });
  } catch (e) {
    results.push({
      json: {
        ...item,
        id: null,
        _db_insert_error: e.message
      }
    });
  }
}

return results;

// TRF_BuildSummary V4 - Fixed: use DB_InsertItem.all() for multi-item support
// Get ALL inserted items from DB_InsertItem (not $input which only has last node's output)
let preparedItems = [];
try {
  const dbItems = $('DB_InsertItem').all();
  preparedItems = dbItems.map(i => i.json);
} catch(e) {
  // Fallback to input if DB_InsertItem reference fails
  preparedItems = $input.all().map(i => i.json);
}

const firstExtract = $('TRF_ExtractItems').first().json || {};
const envelope = firstExtract.envelope || preparedItems[0]?.envelope || {};
const pendingClarification = $('TRF_ProcessExtraction').first().json?.clarification_question || null;

// Check if user has master password
let hasMasterPassword = false;
try {
  const prefsResult = $('DB_FetchPrefs').all();
  if (prefsResult && prefsResult.length > 0) {
    const scope = prefsResult[0].json.lead_time_scope || '';
    hasMasterPassword = scope.startsWith('master_pwd:');
  }
} catch(e) {}

function formatDateTime(isoStr) {
  if (!isoStr) return 'sem data';
  const d = new Date(isoStr);
  return d.toLocaleString('pt-BR', {
    timeZone: 'America/Belem',
    day: '2-digit', month: '2-digit', year: 'numeric',
    hour: '2-digit', minute: '2-digit', hour12: false
  });
}

const SENSITIVE_WORDS = ['senha', 'password', 'pin', 'código', 'codigo', 'segredo', 'secret', 'chave', 'token', 'acesso', 'banco', 'conta', 'agência', 'agencia', 'pix', 'cartão', 'cartao', 'cpf', 'cnpj', 'rg'];
function isSensitive(title, value) {
  const combined = ((title || '') + ' ' + (value || '')).toLowerCase();
  return SENSITIVE_WORDS.some(kw => combined.includes(kw));
}

let hasSensitiveItem = false;
let summary = '';
const itemCount = preparedItems.length;

if (itemCount === 0) {
  summary = 'Não consegui identificar nenhum item para salvar. Pode reformular?';
} else if (itemCount === 1) {
  const item = preparedItems[0];
  const type = item.type;

  if (isSensitive(item.title, item.value)) hasSensitiveItem = true;

  if (type === 'reminder' || type === 'event') {
    const dueAt = formatDateTime(item.event_datetime);
    summary = '✅ ' + (type === 'reminder' ? 'Lembrete' : 'Evento') + ' criado!\n📝 ' + item.title + '\n⏰ ' + dueAt;
    if (item.google_meet_link) {
      summary += '\n📹 Meet: ' + item.google_meet_link;
    }
    if (item.attendees && item.attendees.length > 0) {
      summary += '\n👥 Convidados: ' + item.attendees.join(', ');
    }
    if (item.extra_reminders && item.extra_reminders.length > 0) {
      const reminderTexts = item.extra_reminders.map(m => m >= 60 ? (m/60) + 'h antes' : m + 'min antes');
      summary += '\n🔔 Alertas: ' + reminderTexts.join(', ');
    }
    summary += '\n📅 Sincronizado com Google Calendar';
  } else if (type === 'task') {
    summary = '✅ Tarefa criada!\n📋 ' + item.title;
    if (item.event_datetime) {
      summary += '\n📅 Prazo: ' + formatDateTime(item.event_datetime);
    }
    summary += '\n📋 Sincronizado com Google Tasks';
  } else if (type === 'note') {
    summary = '✅ Nota salva!\n📝 ' + item.title;
  }
} else {
  summary = '✅ ' + itemCount + ' itens criados:\n';
  preparedItems.forEach((item, idx) => {
    if (isSensitive(item.title, item.value)) hasSensitiveItem = true;
    const emoji = (item.type === 'reminder' || item.type === 'event') ? '⏰' : item.type === 'task' ? '📋' : '📝';
    let line = emoji + ' ' + item.title;
    if (item.event_datetime) {
      line += ' — ' + formatDateTime(item.event_datetime);
    }
    if (item.google_meet_link) {
      line += ' 📹';
    }
    if (item.type === 'reminder' || item.type === 'event') line += ' [Calendar]';
    else if (item.type === 'task') line += ' [Tasks]';
    summary += line + '\n';
  });
}

if (hasSensitiveItem && !hasMasterPassword) {
  summary += '\n\n🔐 Essa informação é sensível! Para protegê-la, cadastre uma contrasenha: "minha contrasenha é [sua senha]"';
}
if (pendingClarification) {
  summary += '\n⚠️ ' + pendingClarification;
}

return {
  json: {
    summary: summary,
    envelope: envelope,
    items_count: itemCount
  }
};

// TRF_ExtractItems - Extract items_to_create array for loop
const input = $json;
const items = input.items_to_create || [];
const envelope = input.envelope;

// If no items to create, return empty to skip the loop
if (items.length === 0) {
  return [];
}

// Return each item as a separate output with owner_phone from envelope
return items.map(item => ({
  json: {
    item: {
      ...item,
      owner_phone: item.owner_phone || envelope.from_phone
    },
    envelope: envelope
  }
}));

const item = $input.item.json;
const itemType = item.type;
let syncTarget = 'none';
if (itemType === 'reminder' && item.event_datetime) {
  syncTarget = 'calendar';
} else if (itemType === 'task') {
  syncTarget = 'tasks';
}
return [{
  json: {
    ...item,
    _sync_target: syncTarget
  }
}];

