={{
(function() {
  const item = $json;
  const startTime = item.event_datetime;
  const duration = item.duration_minutes || 60;
  const endMs = new Date(startTime).getTime() + duration * 60 * 1000;
  const endTime = new Date(endMs).toISOString();

  const event = {
    summary: item.title,
    description: item.value || '',
    start: { dateTime: startTime, timeZone: 'America/Belem' },
    end: { dateTime: endTime, timeZone: 'America/Belem' }
  };

  // Google Meet
  if (item.add_google_meet) {
    event.conferenceData = {
      createRequest: {
        requestId: (item.id || Date.now()).toString(),
        conferenceSolutionKey: { type: 'hangoutsMeet' }
      }
    };
  }

  // Attendees (emails)
  if (item.attendees && item.attendees.length > 0) {
    event.attendees = item.attendees.map(email => ({ email: email.trim() }));
  }

  // Custom reminders
  if (item.extra_reminders && item.extra_reminders.length > 0) {
    event.reminders = {
      useDefault: false,
      overrides: item.extra_reminders.map(r => ({
        method: 'popup',
        minutes: r
      }))
    };
  }

  return event;
})()
}}

