// Extrai o Google ID retornado e prepara para salvar no DB
const googleResponse = $input.item.json;
const originalItem = $("IF_NeedsGoogleSync").item.json;
const itemType = originalItem.type;

let calendarEventId = null;
let tasksTaskId = null;
let meetLink = null;

if (itemType === 'reminder') {
  calendarEventId = googleResponse.id || null;
  // Extract Google Meet link if created
  if (googleResponse.conferenceData && googleResponse.conferenceData.entryPoints) {
    const videoEntry = googleResponse.conferenceData.entryPoints.find(e => e.entryPointType === 'video');
    if (videoEntry) {
      meetLink = videoEntry.uri;
    }
  } else if (googleResponse.hangoutLink) {
    meetLink = googleResponse.hangoutLink;
  }
} else if (itemType === 'task') {
  tasksTaskId = googleResponse.id || null;
}

return [{
  json: {
    ...originalItem,
    google_calendar_event_id: calendarEventId,
    google_tasks_task_id: tasksTaskId,
    google_meet_link: meetLink,
    _item_id_to_update: originalItem.id
  }
}];

// DB_SaveGoogleId V6 - persist Google IDs using secure env vars
const item = $input.item.json;
const supabaseUrl = 'https://chtkfksjqcvlxpgyzlsf.supabase.co';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImNodGtma3NqcWN2bHhwZ3l6bHNmIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MjMwODU1NywiZXhwIjoyMDg3ODg0NTU3fQ.DM9wL7MlXRBuM_IYDk3pQ_q-WE7DYuwpqTTywg5A05U';

if (!supabaseUrl || !supabaseKey) {
  return [{ json: { ...item, _google_id_saved: false, _save_error: 'Missing SUPABASE_URL or SUPABASE_KEY environment variables' } }];
}

const itemId = item._item_id_to_update;
if (!itemId) {
  return [{ json: { ...item, _save_error: 'No item ID to update' } }];
}

const updateBody = {};
if (item.google_calendar_event_id) {
  updateBody.google_calendar_event_id = item.google_calendar_event_id;
}
if (item.google_tasks_task_id) {
  updateBody.google_tasks_task_id = item.google_tasks_task_id;
}
if (Object.keys(updateBody).length === 0) {
  return [{ json: item }];
}

try {
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: supabaseUrl + '/rest/v1/items?id=eq.' + itemId,
    headers: {
      apikey: supabaseKey,
      Authorization: 'Bearer ' + supabaseKey,
      'Content-Type': 'application/json',
      Prefer: 'return=representation'
    },
    body: updateBody,
    json: true
  });
  return [{ json: { ...item, _google_id_saved: true } }];
} catch (e) {
  return [{ json: { ...item, _google_id_saved: false, _save_error: e.message } }];
}
